local CS = CS
local LxKVList = LXFW.LxKVList
local LxBaseMgr = require("LApp.Manager.LxBaseMgr")
---@class LGamePool:LxBaseMgr
local LGamePool = LxClass("LGamePool", LxBaseMgr)
