local LSimplePool = LSimplePool

------------------------------------------------------------------
function LGamePool:Initialize()
    LxBaseMgr.Initialize(self)
	---@type LxKVList
    self._simplePoolList = nil
	self._autoClearPoolTimer = nil

    self._rootPoolTrans = CS.FindObject(CS.ROOT_POOL).transform

    self:CreateSimplePool(LPoolTagConst.TAG_SCENE_POOL)
    self:CreateSimplePool(LPoolTagConst.TAG_UI_POOL)
    self:CreateSimplePool(LPoolTagConst.TAG_ICON_CACHE, true)
end

function LGamePool:Dispose()
	self:StopAutoClearLongTimeUnused()

    local simplePoolList = self._simplePoolList
    if simplePoolList then
        for i = 1, simplePoolList:GetSize() do
            local simplePool = simplePoolList:GetAt(i)
            simplePool:ClearPool()
            simplePool:Destroy()
        end
        simplePoolList:RemoveAll()
        simplePoolList = nil
        self._simplePoolList = nil
    end
    LxBaseMgr.Dispose(self)
end

-- 自动清理长时间未使用的对象
function LGamePool:StartAutoClearLongTimeUnused()
	self:StopAutoClearLongTimeUnused()
	
	local checkSpaceTime = 10
	local clearUnusedTime = 30
	
	self._autoClearPoolTimer = LxTimer.LoopTimeCall(function()
		local simplePoolList = self._simplePoolList
		if simplePoolList then
			for i = 1, simplePoolList:GetSize() do
				simplePoolList:GetAt(i):ClearLongTimeUnused(clearUnusedTime)
			end
		end
	end,checkSpaceTime,false,-1)
end

function LGamePool:StopAutoClearLongTimeUnused()
	if self._autoClearPoolTimer then
        LxTimer.LoopTimeStop(self._autoClearPoolTimer)
		self._autoClearPoolTimer = nil 
	end
end
