function LGamePool:ClearSimplePool(poolName)
    local pool = self:GetSimplePool(poolName)
    if pool then
        pool:ClearPool()
    end
end

function LGamePool:ClearAllSimplePool()
    local simplePoolList = self._simplePoolList
    if simplePoolList then
        for i = 1, simplePoolList:GetSize() do
            simplePoolList:GetAt(i):ClearPool()
        end
    end
end

