function LGamePool:PrepareSimplePool(poolName, args, func, poolInitSize)
    local simplePool = self:GetSimplePool(poolName)
    if simplePool then
        simplePool:PreparePoolItem(args, func, poolInitSize)
    else
        LogError("pool " .. poolName .. " lost")
        if (func) then func(nil) end
    end
end

