function LGamePool:MakeItemASync(poolName, args, func)
    local simplePool = self:GetSimplePool(poolName)
    if simplePool then
        simplePool:MakeItemAsync(args, func)
    else
        func(nil,args)
        LogError("game pool " .. poolName .. " not exist ")
    end
end

function LGamePool:MakeItem(poolName, args)
    local simplePool = self:GetSimplePool(poolName)
    if simplePool then
        return simplePool:MakeItem(args)
    end
    LogError("game pool " .. poolName .. " not exist ")
end


function LGamePool:ReturnItem(poolName, itemKey, trans)
    if self._isDestroy then return false end
    local simplePool = self:GetSimplePool(poolName)
    if simplePool then
        return simplePool:ReturnItem(itemKey, trans)
    else
        LogError("game pool " .. poolName .. " not exist ")
    end
    return false
end

------------------------------------------------------------------
function LGamePool:GetSimplePool(poolName)
    local simplePoolList = self._simplePoolList
    if simplePoolList then
        return simplePoolList:GetByKey(poolName)
    end
    return nil
end

function LGamePool:CreateSimplePool(poolName, isObjectActive)
    local simplePoolList = self._simplePoolList
    if not simplePoolList then
        simplePoolList = LxKVList:New()
        self._simplePoolList = simplePoolList
    end
    local simplePool = simplePoolList:GetByKey(poolName)
    if not simplePool then
        simplePool = LSimplePool:New()
        simplePool:InitPool(self._rootPoolTrans, poolName)
        simplePool:SetItemRootTransPos(Vector3(10000,10000,10000) + Vector3(0,1000,0) * simplePoolList:GetSize())
        simplePool:SetObjectActive(isObjectActive)
        simplePoolList:Add(poolName, simplePool)
    end
    return simplePool
end




